import '../Select/Select.scss';

import type { NewDropdownMenuProps } from ':components/NewDropdownMenu';
import { NewDropdownMenu } from ':components/NewDropdownMenu';
import type { MouseEvent } from 'react';
import React, { useRef } from 'react';

import { classNames } from '../../helpers/classnames';
import { getBEMClasses } from '../../helpers/get-bem';
import type { Option } from '../Select/Select.types';
import type { SearchDropdownProps } from './Search.types';

const selectElement = getBEMClasses('dsb__select')[2];
const [optionsClassName, , optionsElement] = selectElement('options');
const [itemClassName] = optionsElement('item');

export const SearchDropdown = <T,>({
	multiple,
	values,
	onChange,
	options,
	onOutsideClick,
	makeOption,
	parentRef,
	isOpen,
	handleSetOpen,
	dataTestId = 'SearchDropdown',
}: SearchDropdownProps<T>): React.JSX.Element => {
	const optionsRef = useRef<HTMLDivElement>(null);

	const onSelectItem = (item: Option<T>) => (event: MouseEvent<HTMLDivElement>) => {
		onChange([item]);
		handleSetOpen(false);
		// надо ли?
		event.stopPropagation();
	};

	const onMultiselectItem = (item: Option<T>) => (event: MouseEvent<HTMLDivElement>) => {
		const itemIndex = values.findIndex(value => item.id === value.id);
		const isAddition = itemIndex === -1;
		const updItems = isAddition ? [...values, item] : values.filter((_value: Option<T>, i: number) => itemIndex !== i);

		onChange(updItems);

		// надо ли?
		event.stopPropagation();
	};

	const makeItem = (item: Option<T>, isSelected: boolean): React.JSX.Element => {
		const className = classNames(itemClassName, {
			selected: isSelected,
		});

		const onClickHandler = multiple ? onMultiselectItem : onSelectItem;

		return (
			<div
				role="button"
				tabIndex={0}
				className={className}
				onClick={onClickHandler(item)}
				onKeyDown={event => {
					if (event.key === 'Enter' || event.key === ' ') {
						event.preventDefault();
						onClickHandler(item);
					}
				}}
				key={item.id.toString()}
			>
				{makeOption(item, isSelected)}
			</div>
		);
	};

	const makeOptions = (selectedItems: Array<Option<T>>, options: Array<Option<T>>): React.JSX.Element => (
		<div className={optionsClassName} ref={optionsRef}>
			{options?.map(item =>
				makeItem(
					item,
					selectedItems.some(i => i.id === item.id),
				),
			)}
		</div>
	);

	const optionsComponents = makeOptions(values, options);

	const MenuProps: NewDropdownMenuProps = {
		targetElement: parentRef,
		align: 'bottom-start',
		verticalOffset: 0,
		isOpen,
		handleSetOpen: handleSetOpen,
		className: 'dsb_options',
		onOutsideClick,
	};

	return (
		<NewDropdownMenu data-testid={dataTestId} {...MenuProps}>
			{optionsComponents}
		</NewDropdownMenu>
	);
};
